#define BLOCK_SIZE 16

__kernel void lud_diagonal(__global float* a, __local float* local_a, const int size, const int offset) {
    int i = get_global_id(0);
    int j, k;

    if (i >= BLOCK_SIZE) return;

    // Load diagonal block into local memory
    for (int row = 0; row < BLOCK_SIZE; row++) {
        for (int col = 0; col < BLOCK_SIZE; col++) {
            local_a[row * BLOCK_SIZE + col] = a[(offset + row) * size + (offset + col)];
        }
    }

    // Synchronize to ensure all data is loaded
    barrier(CLK_LOCAL_MEM_FENCE);

    // Perform LU decomposition on the diagonal block
    for (int diag = 0; diag < BLOCK_SIZE; diag++) {
        if (diag == i) {
            // Update upper triangle (row i, cols j >= i)
            for (j = diag; j < BLOCK_SIZE; j++) {
                float sum = 0.0f;
                for (k = 0; k < diag; k++) {
                    sum += local_a[diag * BLOCK_SIZE + k] * local_a[k * BLOCK_SIZE + j];
                }
                local_a[diag * BLOCK_SIZE + j] -= sum;
            }

            // Compute reciprocal of diagonal element
            float inv_diag = 1.0f / local_a[diag * BLOCK_SIZE + diag];

            // Update lower triangle (rows j > i, col i)
            for (j = diag + 1; j < BLOCK_SIZE; j++) {
                float sum = 0.0f;
                for (k = 0; k < diag; k++) {
                    sum += local_a[j * BLOCK_SIZE + k] * local_a[k * BLOCK_SIZE + diag];
                }
                local_a[j * BLOCK_SIZE + diag] = (local_a[j * BLOCK_SIZE + diag] - sum) * inv_diag;
            }
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    // Write back to global memory
    for (int row = 0; row < BLOCK_SIZE; row++) {
        for (int col = 0; col < BLOCK_SIZE; col++) {
            a[(offset + row) * size + (offset + col)] = local_a[row * BLOCK_SIZE + col];
        }
    }
}

__kernel void lud_perimeter(__global float* a, __local float* local_top, __local float* local_left, __local float* local_div, const int size, const int offset) {
