    // We need the row [offset...offset+BS] at column [j_global...j_global+BS] for the right side
    // And the column [offset...offset+BS] at row [i_global...i_global+BS] is already in diagonal block

    // Actually, the original code loads a specific BSxBS block from the top (pivot row area)
    // For the right perimeter: we need row (offset + i) for i in 0..BS-1, cols j_global..j_global+BS-1
    if (type == 0) {
        // Right perimeter update
        int row = inner_idx; 
        // Load the corresponding row segment from the diagonal block area (top)
        for (int col = 0; col < BLOCK_SIZE; col++) {
            local_top[row * BLOCK_SIZE + col] = a[(offset + row) * size + (j_global + col)];
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        // Compute
        for (int col = 0; col < BLOCK_SIZE; col++) {
            float sum = 0.0f;
            for (int k = 0; k < row; k++) {
                // local_top[k][col] corresponds to a[offset+k][j_global+col] which was updated in previous steps? 
                // No, local_top holds the values from the "top" block which are being updated by the diagonal block.
                // Wait, the algorithm updates the perimeter based on the computed diagonal block.
                // The value a[offset+row][j_global+col] needs to be subtracted by sum(a[offset+row][offset+k] * a[offset+k][j_global+col])
                // a[offset+row][offset+k] is in the diagonal block (left part of the row)
                // a[offset+k][j_global+col] is in the top block (which we are updating)

                // In the original OMP code:
                // temp[i*BS+j] = a[size*(i+offset)+offset+j] -> This is the diagonal block row segment
                // Then it uses temp to update the right block.

                // Let's re-read the OMP logic carefully.
                // It loads "temp" which is the block at (offset, offset) of size BSxBS? 
                // No: temp[i*BS+j] = a[size*(i+offset)+offset+j]. 
                // i goes 0..BS, j goes 0..BS. 
                // So temp is the diagonal block itself? 
                // Yes, AA(_i,_j) in lud_diagonal_omp refers to the diagonal block.
