                // temp[BS*i+k] is a[offset+i][offset+k].
                // BB is a.
                // So it subtracts a[offset+i][offset+k] * a[offset+k][j_global+j].

                // So we need the diagonal block values in local memory.
                // Since the diagonal kernel just finished, they are in global memory.
                // We can load the necessary row of the diagonal block.
            }

            // Optimization: Load the whole diagonal block into local memory for this perimeter kernel?
            // The perimeter kernel runs after diagonal. The diagonal block is stable.
            // We need row 'row' of the diagonal block: a[(offset+row)*size + (offset+k)] for k=0..BS-1
            // And we need column 'col' of the top block? No, we are updating the top block row by row?
            // Actually, the update for element (r, c) in the right block depends on (r, k) in diagonal and (k, c) in right block (previous rows).
            // Since we process row 'row' (which is fixed for this thread in the simplified mapping? No, inner_idx is row).
            // If each thread handles one row of the BSxBS block:

            // Let's stick to the structure: One thread per element in the BSxBS block for simplicity or row-based.
            // The OMP code had a loop over chunk_idx (blocks to the right), then inside loops over i, j.
            // Here we map global_id to (chunk_idx, type, inner_idx).
            // If type=0 (Right), inner_idx = row index within the block (0..BS-1).
            // We need to update the whole row 'inner_idx' of the block at chunk_idx.

            // Reload diagonal row segment
            float diag_row[BLOCK_SIZE];
            for (int k = 0; k < BLOCK_SIZE; k++) {
                diag_row[k] = a[(offset + row) * size + (offset + k)];
            }

            for (int col = 0; col < BLOCK_SIZE; col++) {
                float sum = 0.0f;
                for (int k = 0; k < row; k++) {
                    sum += diag_row[k] * a[(offset + k) * size + (j_global + col)];
