}

__kernel void lud_internal(__global float* a, __local float* local_top, __local float* local_left, const int size, const int offset) {
    int gx = get_global_id(0);
    int gy = get_global_id(1);

    int chunks_in_row = (size - offset - BLOCK_SIZE) / BLOCK_SIZE;

    if (gx >= chunks_in_row || gy >= chunks_in_row) return;

    int i_global = offset + BLOCK_SIZE * (1 + gy);
    int j_global = offset + BLOCK_SIZE * (1 + gx);

    // Load top block segment: rows 0..BS-1 (relative to offset), cols j_global..j_global+BS-1
    // This corresponds to the block immediately above the current internal block
    int row_idx = get_local_id(1);
    int col_idx = get_local_id(0);

    // We need to load the full BSxBS blocks for top and left into local memory for the whole group?
    // The group size is BSxBS.
    // Top block: located at (offset, j_global). Size BSxBS.
    // Left block: located at (i_global, offset). Size BSxBS.

    // Load Top
    for (int r = 0; r < BLOCK_SIZE; r++) {
        for (int c = 0; c < BLOCK_SIZE; c++) {
            local_top[r * BLOCK_SIZE + c] = a[(offset + r) * size + (j_global + c)];
        }
    }

    // Load Left
    for (int r = 0; r < BLOCK_SIZE; r++) {
        for (int c = 0; c < BLOCK_SIZE; c++) {
            local_left[r * BLOCK_SIZE + c] = a[(i_global + r) * size + (offset + c)];
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    // Compute update for element (i, j) within the block
    // i = row_idx, j = col_idx
    float sum = 0.0f;
    for (int k = 0; k < BLOCK_SIZE; k++) {
        sum += local_left[row_idx * BLOCK_SIZE + k] * local_top[k * BLOCK_SIZE + col_idx];
    }

    a[(i_global + row_idx) * size + (j_global + col_idx)] -= sum;
}
